`, "",{"version":3,"sources":["webpack://./src/网游论坛/App.vue"],"names":[],"mappings":"AAiNA,oBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CAGA,iBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CAGA,iBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CAGA,gBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CAEA,oDAEE,qBACF,CAGA,aACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CAEA,cACE,UAAW,CACX,WACF","sourcesContent":["<template>\n  <div class=\"forum-window relative flex flex-col text-[var(--f-text)] h-full overflow-hidden\"\n    :class=\"`theme-${settingsStore.settings.Ztheme}`\"\n    :style=\"{ backgroundColor: 'var(--f-bg)', color: 'var(--f-text)' }\"\n  >\n    <ForumTabs\n      :activeSection=\"forumStore.activeSection\"\n      @switch=\"forumStore.switchSection($event)\"\n      @toggleSettings=\"windowControls.showSettings = !windowControls.showSettings\"\n      @minimize=\"windowControls.requestMinimize = true\"\n    />\n\n    <PostList\n      v-if=\"!forumStore.selectedPostId && !forumStore.showEditor\"\n      :posts=\"forumStore.currentPosts\"\n      @select=\"forumStore.selectPost($event)\"\n      @delete=\"forumStore.deletePost($event)\"\n    />\n\n    <PostDetail\n      v-else-if=\"forumStore.selectedPostId && !forumStore.showEditor\"\n      :post=\"forumStore.selectedPost\"\n      :generating=\"forumStore.isGenerating\"\n      @back=\"forumStore.goBack()\"\n      @generateComments=\"handleGenerateComments\"\n      @addComment=\"forumStore.openCommentEditor()\"\n      @delete=\"handleDeletePost\"\n    />\n\n    <PostEditor\n      v-if=\"forumStore.showEditor\"\n      :mode=\"forumStore.editorMode\"\n      :section=\"forumStore.activeSection\"\n      :postId=\"forumStore.selectedPostId ?? undefined\"\n      @cancel=\"forumStore.closeEditor()\"\n      @submitPost=\"handleSubmitPost\"\n      @submitComment=\"handleSubmitComment\"\n    />\n\n    <!-- 底部操作栏 -->\n    <div v-if=\"!forumStore.selectedPostId && !forumStore.showEditor\" class=\"p-2 flex gap-1\" :style=\"{ borderTop: '1px solid var(--f-border)' }\">\n      <button\n        class=\"flex-1 text-[11px] text-white py-1.5 rounded disabled:opacity-50 transition-colors\"\n        :class=\"forumStore.isGenerating ? 'bg-[var(--f-bg-input)] cursor-wait' : 'bg-[var(--f-accent-bg)] hover:bg-[var(--f-accent-bg-hover)]'\"\n        :disabled=\"forumStore.isGenerating\"\n        @click=\"forumStore.openGenDialog()\"\n      >\n        <i :class=\"forumStore.isGenerating ? 'fa-solid fa-spinner fa-spin' : 'fa-solid fa-robot'\"></i>\n        {{ forumStore.isGenerating ? '生成中...' : 'AI生成帖子' }}\n      </button>\n      <button\n        class=\"text-[11px] px-3 py-1.5 rounded bg-[var(--f-bg-input)] hover:bg-[var(--f-bg-hover)] text-[var(--f-text)]\"\n        :disabled=\"forumStore.isGenerating\"\n        @click=\"forumStore.openPostEditor()\"\n      >\n        <i class=\"fa-solid fa-pen\"></i> 发帖\n      </button>\n    </div>\n\n    <!-- 生成对话框 -->\n    <div v-if=\"forumStore.showGenDialog\" class=\"absolute inset-0 z-20 flex flex-col p-3\" :style=\"{ backgroundColor: 'var(--f-bg)' }\">\n      <div class=\"flex items-center justify-between mb-3\">\n        <span class=\"text-sm font-bold text-[var(--f-text)]\">\n          <i class=\"fa-solid fa-robot text-[var(--f-accent)]\"></i> AI 批量生成帖子\n        </span>\n        <button class=\"text-[var(--f-text-secondary)] hover:text-[var(--f-text)]\" @click=\"forumStore.closeGenDialog()\">\n          <i class=\"fa-solid fa-xmark\"></i>\n        </button>\n      </div>\n      <div class=\"space-y-3 flex-1\">\n        <div>\n          <label class=\"text-[11px] text-[var(--f-text-secondary)] block mb-1\">讨论方向 / 话题关键词（可选，留空则由 AI 自由发挥）</label>\n          <textarea\n            v-model=\"genTopic\"\n            class=\"w-full text-xs px-2 py-1.5 rounded outline-none border focus:border-[var(--f-accent)] resize-none\"\n            :style=\"{ backgroundColor: 'var(--f-bg-input)', color: 'var(--f-text)', borderColor: 'var(--f-border-hover)' }\"\n            rows=\"3\"\n            placeholder=\"例如：最近更新的新副本、PK大赛、装备强化黑幕、生活玩家日常…&#10;多个话题可以用逗号或换行分隔\"\n          ></textarea>\n        </div>\n        <div>\n          <label class=\"text-[11px] text-[var(--f-text-secondary)] block mb-1\">板块：{{ forumStore.activeSectionName }}</label>\n        </div>\n      </div>\n      <button\n        class=\"w-full text-xs text-white py-2 rounded disabled:opacity-50 mt-2 flex items-center justify-center gap-1 transition-colors\"\n        :class=\"forumStore.isGenerating ? 'bg-[var(--f-bg-input)] cursor-wait' : 'bg-[var(--f-accent-bg)] hover:bg-[var(--f-accent-bg-hover)]'\"\n        :disabled=\"forumStore.isGenerating\"\n        @click=\"handleBatchGenerate\"\n      >\n        <i v-if=\"forumStore.isGenerating\" class=\"fa-solid fa-spinner fa-spin\"></i>\n        {{ forumStore.isGenerating ? '生成中，请稍候...' : '开始生成' }}\n      </button>\n    </div>\n\n    <SettingsPanel\n      v-if=\"windowControls.showSettings\"\n      @close=\"windowControls.showSettings = false\"\n    />\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport type { ForumPost, ForumComment } from './types';\nimport { useForumStore } from './stores/forumStore';\nimport { useSettingsStore } from './stores/settingsStore';\nimport { generatePosts, generateComments } from './utils/aiGenerator';\nimport { injectForumContext } from './utils/contextInjector';\nimport ForumTabs from './components/ForumTabs.vue';\nimport PostList from './components/PostList.vue';\nimport PostDetail from './components/PostDetail.vue';\nimport PostEditor from './components/PostEditor.vue';\nimport SettingsPanel from './components/SettingsPanel.vue';\n\nconst forumStore = useForumStore();\nconst settingsStore = useSettingsStore();\n\n// 从 index.ts 通过 app.provide 注入的窗口控制状态\nconst windowControls = inject<{ showSettings: boolean; requestMinimize: boolean }>('windowControls')!;\n\n// 生成对话框的话题输入\nconst genTopic = ref('');\n\nasync function handleBatchGenerate() {\n  forumStore.isGenerating = true;\n  try {\n    const topic = genTopic.value.trim() || undefined;\n    const posts = await generatePosts(forumStore.activeSection, topic);\n    for (const post of posts) {\n      settingsStore.addPost(post);\n    }\n    injectForumContext();\n    toastr.success(`AI生成了${posts.length}个帖子`);\n    forumStore.closeGenDialog();\n    genTopic.value = '';\n  } catch (e) {\n    toastr.error(`生成帖子失败: ${e instanceof Error ? e.message : String(e)}`);\n  } finally {\n    forumStore.isGenerating = false;\n  }\n}\n\nasync function handleGenerateComments() {\n  if (!forumStore.selectedPost) return;\n  forumStore.isGenerating = true;\n  try {\n    const comments = await generateComments(forumStore.activeSection, forumStore.selectedPost);\n    for (const comment of comments) {\n      settingsStore.addComment(forumStore.activeSection, forumStore.selectedPost!.id, comment);\n    }\n    injectForumContext();\n    toastr.success(`AI生成了${comments.length}条评论`);\n  } catch (e) {\n    toastr.error(`生成评论失败: ${e instanceof Error ? e.message : String(e)}`);\n  } finally {\n    forumStore.isGenerating = false;\n  }\n}\n\nfunction handleDeletePost() {\n  if (!forumStore.selectedPostId) return;\n  forumStore.deletePost(forumStore.selectedPostId);\n  injectForumContext();\n}\n\nfunction handleSubmitPost(post: ForumPost) {\n  settingsStore.addPost(post);\n  forumStore.closeEditor();\n  injectForumContext();\n  // 用户发帖后自动生成AI回复\n  if (settingsStore.settings.ZautoAiReply) {\n    triggerAutoAiReply(post.id);\n  }\n}\n\nfunction handleSubmitComment(postId: string, comment: ForumComment) {\n  settingsStore.addComment(forumStore.activeSection, postId, comment);\n  forumStore.closeEditor();\n  injectForumContext();\n  // 用户评论后自动生成AI回复\n  if (settingsStore.settings.ZautoAiReply) {\n    triggerAutoAiReply(postId);\n  }\n}\n\n/** 自动生成AI回复（用户发帖/评论后触发） */\nasync function triggerAutoAiReply(postId: string) {\n  const post = settingsStore.settings.Zposts[forumStore.activeSection].find(p => p.id === postId);\n  if (!post) return;\n  forumStore.isGenerating = true;\n  try {\n    const comments = await generateComments(forumStore.activeSection, post);\n    for (const comment of comments) {\n      settingsStore.addComment(forumStore.activeSection, postId, comment);\n    }\n    injectForumContext();\n    toastr.success(`AI自动回复了${comments.length}条评论`);\n  } catch (e) {\n    console.warn('[网游论坛] 自动AI回复失败:', e);\n  } finally {\n    forumStore.isGenerating = false;\n  }\n}\n</script>\n\n<style>\n/* ─── 主题 CSS 变量定义 ─── */\n\n/* 经典暗黑（默认） */\n.theme-classic-dark {\n  --f-bg: #111827;\n  --f-bg-card: #1f2937;\n  --f-bg-input: #374151;\n  --f-bg-hover: #4b5563;\n  --f-text: #e5e7eb;\n  --f-text-secondary: #9ca3af;\n  --f-text-muted: #6b7280;\n  --f-border: #374151;\n  --f-border-hover: #4b5563;\n  --f-accent: #60a5fa;\n  --f-accent-bg: #2563eb;\n  --f-accent-bg-hover: #3b82f6;\n  --f-accent-dim: #1e3a5f;\n  --f-author: #4ade80;\n  --f-danger: #f87171;\n  --f-danger-bg: #7f1d1d;\n}\n\n/* 赛博朋克 */\n.theme-cyberpunk {\n  --f-bg: #0a0a1a;\n  --f-bg-card: #12122e;\n  --f-bg-input: #1a1a42;\n  --f-bg-hover: #252560;\n  --f-text: #d0d0ff;\n  --f-text-secondary: #8888cc;\n  --f-text-muted: #555588;\n  --f-border: #2a2a5e;\n  --f-border-hover: #3a3a7e;\n  --f-accent: #00ffff;\n  --f-accent-bg: #0099bb;\n  --f-accent-bg-hover: #00bbdd;\n  --f-accent-dim: #003344;\n  --f-author: #ff00ff;\n  --f-danger: #ff3366;\n  --f-danger-bg: #4d0022;\n}\n\n/* 蒸汽波 */\n.theme-vaporwave {\n  --f-bg: #1a0a2e;\n  --f-bg-card: #2d1b4e;\n  --f-bg-input: #3d2d6e;\n  --f-bg-hover: #4d3d8e;\n  --f-text: #f0e0ff;\n  --f-text-secondary: #c8a0e0;\n  --f-text-muted: #8866aa;\n  --f-border: #4d3d7e;\n  --f-border-hover: #5d4d9e;\n  --f-accent: #ff71ce;\n  --f-accent-bg: #b967ff;\n  --f-accent-bg-hover: #cc77ff;\n  --f-accent-dim: #4a1942;\n  --f-author: #01cdfe;\n  --f-danger: #ff6b6b;\n  --f-danger-bg: #4a1919;\n}\n\n/* 终端绿 */\n.theme-terminal {\n  --f-bg: #0a0a0a;\n  --f-bg-card: #141414;\n  --f-bg-input: #1e1e1e;\n  --f-bg-hover: #282828;\n  --f-text: #33ff33;\n  --f-text-secondary: #22cc22;\n  --f-text-muted: #117711;\n  --f-border: #224422;\n  --f-border-hover: #336633;\n  --f-accent: #33ff33;\n  --f-accent-bg: #22aa22;\n  --f-accent-bg-hover: #33cc33;\n  --f-accent-dim: #113311;\n  --f-author: #88ff88;\n  --f-danger: #ff4444;\n  --f-danger-bg: #330000;\n}\n\n.theme-terminal .fa-solid,\n.theme-terminal .fa-robot {\n  color: var(--f-accent);\n}\n\n/* 简约白 */\n.theme-light {\n  --f-bg: #f3f4f6;\n  --f-bg-card: #ffffff;\n  --f-bg-input: #e5e7eb;\n  --f-bg-hover: #d1d5db;\n  --f-text: #111827;\n  --f-text-secondary: #4b5563;\n  --f-text-muted: #9ca3af;\n  --f-border: #d1d5db;\n  --f-border-hover: #9ca3af;\n  --f-accent: #2563eb;\n  --f-accent-bg: #2563eb;\n  --f-accent-bg-hover: #1d4ed8;\n  --f-accent-dim: #dbeafe;\n  --f-author: #059669;\n  --f-danger: #dc2626;\n  --f-danger-bg: #fee2e2;\n}\n\n.forum-window {\n  width: 100%;\n  height: 100%;\n}\n</style>\n"],"sourceRoot":""}]);
